+import assert from "node:assert/strict";
+import { describe, test } from "node:test";
+import { object } from "./constructs.ts";
+import { withDefault } from "./modifiers.ts";
+import { conditionalOption, option, optionalWhen, requiredWhen } from "./primitives.ts";
+import { getDocPage, parseSync, suggestSync } from "./parser.ts";
+import { boolean, string } from "./valueparser.ts";
+
+describe("conditional options", () => {
+  test("resolves object keys and flag names, including wrapped options", () => {
+    const parser = object({
+      enabled: withDefault(option("--enabled"), false),
+      output: requiredWhen("--enabled", "--output", string()),
+    });
+    const missing = parseSync(parser, []);
+    assert.ok(!missing.success);
+    assert.match(String(missing.error), /requires option.*--enabled/);
+    const result = parseSync(parser, ["--enabled", "--output", "file"]);
+    assert.ok(result.success);
+  });
+
+  test("supports values, compounds, empty compounds, and missing keys", () => {
+    const parser = object({
+      format: withDefault(option("--format", string()), "text"),
+      output: conditionalOption({ option: "format", value: "json" }, "--output", string()),
+      both: conditionalOption({ allOf: [] }, "--both", string()),
+      never: conditionalOption({ anyOf: [] }, "--never", string()),
+      absent: conditionalOption("missing", "--absent", string()),
+    });
+    const suggestions = suggestSync(parser, [""]).map((s) => s.kind === "literal" ? s.text : "");
+    assert.ok(!suggestions.includes("--output"));
+    assert.ok(suggestions.includes("--both"));
+    assert.ok(!suggestions.includes("--never"));
+    assert.ok(!suggestions.includes("--absent"));
+    const result = parseSync(parser, ["--format", "json", "--output", "file"]);
+    assert.ok(result.success);
+  });
+
+  test("hides optional dependencies but permits their explicit use", () => {
+    const parser = object({
+      verbose: option("--verbose"),
+      detail: optionalWhen("verbose", "--detail", string()),
+    });
+    const doc = getDocPage(parser);
+    assert.ok(doc);
+    assert.ok(!doc.sections.flatMap((section) => section.entries).some((entry) => String(entry.term).includes("--detail")));
+    const result = parseSync(parser, ["--detail", "all"]);
+    assert.ok(result.success);
+  });
+
+  test("rejects a dependent option when its dependee was explicitly falsy", () => {
+    const parser = object({
+      enabled: option("--enabled", boolean()),
+      output: optionalWhen("enabled", "--output", string()),
+    });
+    const result = parseSync(parser, ["--enabled=false", "--output", "file"]);
+    assert.ok(!result.success);
+  });
+});
