+import type { OptionName, Usage, UsageTerm } from "./usage.ts";
+
+/** A condition on one other option. */
+export interface OptionDependency {
+  readonly option: string;
+  readonly value?: unknown;
+}
+
+/** Conditions controlling the availability of an option. */
+export interface DependsOn {
+  readonly option?: string;
+  readonly value?: unknown;
+  readonly anyOf?: readonly OptionDependency[];
+  readonly allOf?: readonly OptionDependency[];
+  readonly required?: boolean;
+}
+
+/** A condition accepted by the conditional option helpers. */
+export type OptionCondition = string | OptionDependency | DependsOn;
+
+/** Converts a helper condition to option dependency metadata. */
+export function normalizeDependsOn(
+  condition: OptionCondition,
+  required?: boolean,
+): DependsOn {
+  const dependency = typeof condition === "string"
+    ? { option: condition }
+    : condition;
+  return required === undefined ? dependency : { ...dependency, required };
+}
+
+/** Finds the first option term in a parser usage tree. */
+export function findOptionTerm(usage: Usage): Extract<UsageTerm, { type: "option" }> | undefined {
+  for (const term of usage) {
+    if (term.type === "option") return term;
+    if (term.type === "optional" || term.type === "multiple") {
+      const nested = findOptionTerm(term.terms);
+      if (nested) return nested;
+    } else if (term.type === "exclusive") {
+      for (const terms of term.terms) {
+        const nested = findOptionTerm(terms);
+        if (nested) return nested;
+      }
+    }
+  }
+  return undefined;
+}
+
+/** Maps object keys and option names to their current parser states. */
+export interface DependencyContext {
+  readonly values: ReadonlyMap<string, unknown>;
+  readonly provided: ReadonlySet<string>;
+  readonly names: ReadonlyMap<string, OptionName>;
+}
+
+function isResult(value: unknown): value is { readonly success: boolean; readonly value?: unknown } {
+  return typeof value === "object" && value !== null && "success" in value;
+}
+
+/** Extracts a value and whether it was supplied from a parser state. */
+export function unwrapDependencyState(state: unknown): { readonly value: unknown; readonly provided: boolean } {
+  if (Array.isArray(state)) return state.length === 0
+    ? { value: undefined, provided: false }
+    : unwrapDependencyState(state[0]);
+  if (typeof state === "object" && state !== null && "result" in state) {
+    return unwrapDependencyState((state as { readonly result: unknown }).result);
+  }
+  if (isResult(state)) return state.success
+    ? { value: state.value, provided: true }
+    : { value: undefined, provided: false };
+  return { value: state, provided: state !== undefined };
+}
+
+function satisfiesOne(dependency: OptionDependency, context: DependencyContext): boolean {
+  if (!context.values.has(dependency.option)) return false;
+  const value = context.values.get(dependency.option);
+  return "value" in dependency ? value === dependency.value : Boolean(value);
+}
+
+/** Checks whether a dependency configuration is currently satisfied. */
+export function isDependencySatisfied(
+  dependency: DependsOn | undefined,
+  context: DependencyContext,
+): boolean {
+  if (!dependency) return true;
+  const single = dependency.option === undefined ? true : satisfiesOne(dependency, context);
+  const anyOf = dependency.anyOf === undefined
+    ? true
+    : dependency.anyOf.some((item) => satisfiesOne(item, context));
+  const allOf = dependency.allOf === undefined
+    ? true
+    : dependency.allOf.every((item) => satisfiesOne(item, context));
+  return single && anyOf && allOf;
+}
+
+/** Returns a user-facing name for the first referenced dependee. */
+export function dependencyOptionName(
+  dependency: DependsOn,
+  context: DependencyContext,
+): string {
+  const item = dependency.option === undefined
+    ? dependency.anyOf?.[0] ?? dependency.allOf?.[0]
+    : dependency;
+  if (!item) return "the required option";
+  return context.names.get(item.option) ?? item.option;
+}
